{
  printf '# Changelog\n\n'
  feats=''
  fixes=''
  others=''
  while IFS= read -r line || [[ -n "$line" ]]; do
    [[ -z "$line" ]] && continue
    type=${line%%(*}
    rest=${line#*(}
    scope=${rest%%)*}
    msg=${line#*: }
    item="- ${scope}: ${msg}"
    case "$type" in
      feat) feats+="$item"$'\n' ;;
      fix) fixes+="$item"$'\n' ;;
      *) others+="$item"$'\n' ;;
    esac
  done < "$infile"

  printf '## Features\n'
  [[ -n "$feats" ]] && printf '%s' "$feats"
  printf '\n## Bug Fixes\n'
  [[ -n "$fixes" ]] && printf '%s' "$fixes"
  printf '\n## Other\n'
  [[ -n "$others" ]] && printf '%s' "$others"
} > "$outfile"
cat "$outfile"

